import{_ as t,o,c as a,Q as e}from"./chunks/framework.d2c27d76.js";const g=JSON.parse('{"title":"GitHub Actions","description":"","frontmatter":{"layout":"doc","topic":"Github Actions","brief":"GitHub Actions是GitHub平台提供的一项功能，用于自动化构建、测试和部署软件项目。它可以让我们在特定的事件（如push 、pull request 事件等）或条件发生（如特定时间执行等）时执行自定义的工作流程。","language":["yml"],"tag":["CI/CD","Github Actions","Workflow"]},"headers":[],"relativePath":"zh/post/github_actions.draft.md","filePath":"zh/post/github_actions.draft.md","lastUpdated":1699459403000}'),r={name:"zh/post/github_actions.draft.md"},i=e('<h1 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to &quot;GitHub Actions&quot;">​</a></h1><blockquote><p>本页介绍<code>GitHub Actions</code>。</p></blockquote><h2 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h2><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/quickstart#introduction" target="_blank" rel="noreferrer">快速入门</a>了解更多信息</p></blockquote><ol><li>如果该目录不存在，则在存储库中创建一个<code>.github/workflows</code>目录。</li><li>在<code>.github/workflows</code>目录中，创建一个<code>&lt;workflow-name&gt;.yml</code>文件来定义工作流程配置。</li><li>当指定的事件发生时，工作流程将自动触发。</li></ol><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><h3 id="工作流" tabindex="-1">工作流 <a class="header-anchor" href="#工作流" aria-label="Permalink to &quot;工作流&quot;">​</a></h3><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/using-workflows" target="_blank" rel="noreferrer">使用工作流</a>了解更多信息</p></blockquote><ul><li>工作流由<code>.github/workflows</code> 下的<code>&lt;workflow-name&gt;.yml</code>文件定义，并将在存储库中的<strong>事件触发</strong>时运行，也可以<strong>手动触发</strong>或按<strong>定义的计划</strong>触发。</li><li>一个存储库可以有多个工作流，每个工作流可以执行一组不同的任务</li></ul><h3 id="事件" tabindex="-1">事件 <a class="header-anchor" href="#事件" aria-label="Permalink to &quot;事件&quot;">​</a></h3><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/using-workflows/events-that-trigger-workflows" target="_blank" rel="noreferrer">触发工作流的事件</a>了解更多信息</p></blockquote><ul><li>TODO</li></ul><h3 id="作业" tabindex="-1">作业 <a class="header-anchor" href="#作业" aria-label="Permalink to &quot;作业&quot;">​</a></h3><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/using-jobs" target="_blank" rel="noreferrer">使用作业</a>了解更多信息</p></blockquote><ul><li>TODO</li></ul><h3 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h3><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/creating-actions" target="_blank" rel="noreferrer">创建操作</a>了解更多信息</p></blockquote><ul><li>TODO</li></ul><h3 id="运行器" tabindex="-1">运行器 <a class="header-anchor" href="#运行器" aria-label="Permalink to &quot;运行器&quot;">​</a></h3><blockquote><p>参阅<a href="https://docs.github.com/zh/actions/using-github-hosted-runners/about-github-hosted-runners" target="_blank" rel="noreferrer">使用 GitHub 托管的运行器</a>了解更多信息</p></blockquote><ul><li>TODO</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://github.com/marketplace?type=actions" target="_blank" rel="noreferrer">GitHub Marketplace</a></li><li><a href="https://docs.github.com/en/actions" target="_blank" rel="noreferrer">GitHub Actions documentation</a></li></ul>',23),l=[i];function c(n,s,h,u,b,d){return o(),a("div",null,l)}const k=t(r,[["render",c]]);export{g as __pageData,k as default};
